static inline int qt_idx(int m, int ar, int ac, int tr, int tc, int a) {
    return (((m * QT_ROWS + ar) * QT_COLS + ac) * QT_ROWS + tr)
           * QT_COLS * QT_ACTIONS + tc * QT_ACTIONS + a;
}

static inline int qt_best_action(int ac, int ar, int tc, int tr, int m) {
    int best_a = 0;
    short best_v = q_table[qt_idx(m, ar, ac, tr, tc, 0)];
    short v;
    v = q_table[qt_idx(m, ar, ac, tr, tc, 1)]; if (v > best_v) { best_v = v; best_a = 1; }
    v = q_table[qt_idx(m, ar, ac, tr, tc, 2)]; if (v > best_v) { best_v = v; best_a = 2; }
    v = q_table[qt_idx(m, ar, ac, tr, tc, 3)]; if (v > best_v) { best_v = v; best_a = 3; }
    return best_a;
}

